content.text:
/* Hex */
color: #ef4444;
color: #f00;            /* short form — #rrggbb abbreviated */

/* RGB — modern space syntax */
color: rgb(59 130 246);
color: rgb(59 130 246 / 50%);    /* 50% alpha */
color: rgb(59 130 246 / 0.5);    /* same — decimal ok */

/* HSL */
color: hsl(221 83% 53%);         /* blue */
color: hsl(221 83% 53% / 0.8);   /* 80% opacity */

/* OKLCH — perceptually uniform, P3 gamut access */
color: oklch(0.65 0.20 260);     /* L=0.65, C=0.20, H=260° */
color: oklch(0.65 0.20 260 / 0.9);

/* currentColor — inherits the text color */
border: 1px solid currentColor;
fill: currentColor;              /* SVG icons inherit button text color */

background-color: transparent;   /* fully transparent — same as rgb(0 0 0 / 0) */
color: inherit;                   /* inherit from parent */
border-color: currentColor;       /* matches current text color */

/* Avoid named colors in production — use hex/oklch for consistency */
/* Exception: keyword values like transparent are fine */

.card {
  background-color: #1e293b;  /* element background */
  color: #f8fafc;             /* text (and currentColor) */
}

/* background-color is not inherited; color IS inherited */
.card p {
  /* inherits color: #f8fafc from .card */
  /* does NOT inherit background-color */
}

.hero {
  background-image: linear-gradient(to right, #3b82f6, #8b5cf6);
  /* Direction: to right, to bottom right, 135deg, etc. */
}

/* Multiple color stops */
.sunset {
  background-image: linear-gradient(
    to bottom,
    #f97316 0%,
    #ef4444 50%,
    #7c3aed 100%
  );
}

/* Hard stop — no blend between colors */
.stripe {
  background-image: linear-gradient(
    90deg,
    #3b82f6 50%,
    #1e293b 50%
  );
}

.spotlight {
  background-image: radial-gradient(
    circle at 30% 40%,    /* shape and position */
    #f59e0b 0%,
    #ef4444 60%,
    transparent 100%
  );
}

.ellipse {
  background-image: radial-gradient(
    ellipse closest-side,
    #10b981,
    #0f172a
  );
}

.pie {
  background-image: conic-gradient(
    #ef4444 0% 25%,    /* 25% red */
    #3b82f6 25% 60%,   /* 35% blue */
    #10b981 60% 100%   /* 40% green */
  );
  border-radius: 50%;  /* make it a circle */
}

.color-wheel {
  background-image: conic-gradient(red, yellow, lime, cyan, blue, magenta, red);
  border-radius: 50%;
}

.hero {
  background-image: url('/assets/hero.jpg');
  background-size: cover;        /* fill the element */
  background-position: center;   /* center the crop */
  background-repeat: no-repeat;  /* don't tile */
}

/* Shorthand — order: color image position/size repeat attachment origin/clip */
.hero {
  background: #1e293b url('/assets/hero.jpg') center/cover no-repeat;
}

.avatar {
  background-image: url('/avatar.png');
  background-size: 48px 48px;   /* explicit for small icons */
  background-repeat: no-repeat;
  width: 48px;
  height: 48px;
}

.banner {
  background-image: url('/banner.jpg');
  background-size: cover;
  background-position: center 30%;   /* align crop 30% from top */
  aspect-ratio: 16 / 9;
}

.overlay {
  background:
    /* Layer 1 — top: semi-transparent gradient */
    linear-gradient(to bottom, rgba(0,0,0,0.4), transparent),
    /* Layer 2 — bottom: photo */
    url('/photo.jpg') center/cover no-repeat,
    /* Fallback color */
    #1e293b;
}

/* Texture + color */
.textured {
  background:
    url('/noise.png') repeat,
    oklch(0.3 0.1 260);
}

.parallax {
  background-image: url('/hero.jpg');
  background-size: cover;
  background-attachment: fixed;   /* image fixed relative to viewport — parallax effect */
  /* scroll (default) | fixed | local */
}

:root {
  /* Primitive palette */
  --blue-500: oklch(0.60 0.22 260);
  --blue-600: oklch(0.53 0.22 260);
  --slate-900: oklch(0.20 0.02 260);
  --slate-50:  oklch(0.97 0.01 260);

  /* Semantic tokens */
  --color-primary:       var(--blue-500);
  --color-primary-hover: var(--blue-600);
  --color-surface:       var(--slate-900);
  --color-on-surface:    var(--slate-50);
  --color-border:        oklch(0.30 0.02 260 / 0.5);
}

@media (prefers-color-scheme: dark) {
  :root {
    --color-surface: oklch(0.15 0.02 260);
    --color-on-surface: oklch(0.97 0.01 260);
  }
}

.button {
  background-color: var(--color-primary);
  color: var(--color-on-surface);
  border: 1px solid var(--color-border);
}

.button:hover {
  background-color: var(--color-primary-hover);
}

// theme.service.ts
@Injectable({ providedIn: 'root' })
export class ThemeService {
  private theme = signal<'dark' | 'light'>('dark');

  toggle() {
    this.theme.update(t => t === 'dark' ? 'light' : 'dark');
    document.documentElement.dataset['theme'] = this.theme();
  }
}

// card.component.scss
:host {
  background-color: var(--color-surface);
  color: var(--color-text);
  border: 1px solid oklch(from var(--color-text) l c h / 0.15);
}

/* Automatic — follows OS preference */
@media (prefers-color-scheme: dark) {
  :root {
    --color-surface: #0f172a;
    --color-text: #f8fafc;
  }
}

/* Manual — add class to html element */
html.dark {
  --color-surface: #0f172a;
  --color-text: #f8fafc;
}

.modal-overlay {
  /* Use rgba for overlay — don't use opacity or the content becomes transparent too */
  background-color: rgb(0 0 0 / 0.6);
}

.disabled-button {
  /* opacity affects the whole element including text — intentional here */
  opacity: 0.4;
  cursor: not-allowed;
}

.button-hover {
  /* Mix 20% white into the primary color */
  background-color: color-mix(in oklch, var(--color-primary) 80%, white);
}

.muted {
  /* Mix 30% transparent for a lighter shade */
  color: color-mix(in srgb, var(--color-text) 70%, transparent);
}

/* Compare two colors at 50% in different color spaces */
.blend-oklch {
  background: color-mix(in oklch, #ef4444, #3b82f6);   /* purple — perceptually centered */
}
.blend-srgb {
  background: color-mix(in srgb, #ef4444, #3b82f6);    /* grey/brown — sRGB midpoint */
}

:root {
  --color-primary: oklch(0.6 0.22 260);
}

.button-hover {
  /* Lighten: increase L by 0.1 */
  background-color: oklch(from var(--color-primary) calc(l + 0.1) c h);
}

.button-active {
  /* Darken: decrease L by 0.05 */
  background-color: oklch(from var(--color-primary) calc(l - 0.05) c h);
}

.button-muted {
  /* Desaturate: halve the chroma */
  background-color: oklch(from var(--color-primary) l calc(c * 0.5) h);
}

.card {
  background-color: #1e293b;
  background-clip: padding-box;  /* stop at padding edge — default */
  /* border-box | padding-box | content-box */
}

/* Gradient text effect */
.gradient-text {
  background-image: linear-gradient(135deg, #3b82f6, #8b5cf6);
  background-clip: text;
  -webkit-background-clip: text;  /* Safari */
  color: transparent;
}

.with-border-bg {
  background-image: url('/pattern.png');
  background-origin: border-box;   /* position relative to border edge */
  background-clip: border-box;     /* allow bg to show through border area */
  border: 8px dashed transparent;
}

/* Example: check that button meets AA contrast */
.button {
  background-color: oklch(0.60 0.22 260);  /* #2563eb-ish */
  color: white;
  /* Contrast: ~5.5:1 — passes AA */
}

/* Low contrast — fails AA */
.bad-button {
  background-color: oklch(0.80 0.15 260);  /* light blue */
  color: white;
  /* Contrast: ~2.2:1 — fails! */
}

.card {
  background-color: var(--color-surface);
  box-shadow:
    0 1px 2px rgb(0 0 0 / 0.05),
    0 4px 8px rgb(0 0 0 / 0.08),
    0 16px 32px rgb(0 0 0 / 0.04);
}

/* Inset shadow — pressed state */
.input:focus {
  box-shadow: inset 0 0 0 2px var(--color-primary);
}

/* Use semi-transparent black/white so shadows adapt to any background */
/* Avoid hard-coded grey shadows (#ccc) — they look wrong on colored backgrounds */

// Do NOT do this (security risk — style injection)
// <div [style.background-image]="'url(' + user.photo + ')'">

// Instead use DomSanitizer for dynamic URLs
import { DomSanitizer, SafeStyle } from '@angular/platform-browser';

@Component({
  template: `<div [style.background-image]="safeBg()"></div>`
})
export class AvatarComponent {
  @Input() photoUrl = '';

  private sanitizer = inject(DomSanitizer);

  safeBg(): SafeStyle {
    return this.sanitizer.bypassSecurityTrustStyle(
      `url('${this.photoUrl}')`
    );
  }
}

:host {
  background-image: url('/assets/textures/noise.png');
  /* Path relative to the deployed root, not the component file */
}
